#include <turbojs_embed.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define CHECK(x) do{if(!(x)){fprintf(stderr,"check failed %s:%d: %s\n",__FILE__,__LINE__,#x);return 1;}}while(0)
int main(void){const TurboJSEmbedAPI*a=TurboJS_GetEmbedAPI(TURBOJS_EMBED_ABI_VERSION);unsigned cycles=200,i;const char*env=getenv("TURBOJS_STRESS_CYCLES");if(env&&*env)cycles=(unsigned)strtoul(env,NULL,10);CHECK(a);for(i=0;i<cycles;i++){TurboJSEmbedConfig c={sizeof(c),TURBOJS_EMBED_API_VERSION,8u*1024u*1024u,512u*1024u};TurboJSEngine*e=a->create(&c);int64_t r=0;CHECK(e);CHECK(a->eval_i64(e,"let a=[]; for(let i=0;i<2000;i++) a.push({i,s:'x'+i}); a.length",strlen("let a=[]; for(let i=0;i<2000;i++) a.push({i,s:'x'+i}); a.length"),&r)==TURBOJS_EMBED_OK);CHECK(r==2000);CHECK(a->eval_i64(e,"try { throw new RangeError('stress'); } catch(e) { 7 }",strlen("try { throw new RangeError('stress'); } catch(e) { 7 }"),&r)==TURBOJS_EMBED_OK);CHECK(r==7);a->collect_garbage(e);a->destroy(e);}/* deterministic OOM/exception boundary */{TurboJSEmbedConfig c={sizeof(c),TURBOJS_EMBED_API_VERSION,256u*1024u,128u*1024u};TurboJSEngine*e=a->create(&c);int64_t r=0;TurboJSEmbedStatus s;CHECK(e);s=a->eval_i64(e,"let a=[]; for(let i=0;i<100000;i++) a.push('xxxxxxxxxxxxxxxxxxxxxxxx'); a.length",strlen("let a=[]; for(let i=0;i<100000;i++) a.push('xxxxxxxxxxxxxxxxxxxxxxxx'); a.length"),&r);CHECK(s==TURBOJS_EMBED_EXCEPTION||s==TURBOJS_EMBED_OK);a->destroy(e);}printf("runtime stress passed: %u lifecycle cycles\n",cycles);return 0;}
